'use client';

import { useState, useEffect, useCallback, useRef } from 'react';
import { useRouter } from 'next/navigation';
import { useAuth } from '@/context/AuthContext';
import {
  collection, query, where, getDocs, addDoc, doc, setDoc, updateDoc, increment
} from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { UserProfile } from '@/lib/types';
import SwipeCard, { SwipeCardHandle } from '@/components/SwipeCard';
import BottomNav from '@/components/BottomNav';

export default function SwipePage() {
  const { user, profile, loading } = useAuth();
  const router = useRouter();
  const [profiles, setProfiles] = useState<UserProfile[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [loadingProfiles, setLoadingProfiles] = useState(true);
  const [showMatch, setShowMatch] = useState<UserProfile | null>(null);
  const [nimInsights, setNimInsights] = useState<Record<string, string>>({});
  const [toast, setToast] = useState<string | null>(null);
  const topCardRef = useRef<SwipeCardHandle | null>(null);
  const toastTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    if (!loading && !user) router.push('/auth');
  }, [user, loading, router]);

  const fetchProfiles = useCallback(async () => {
    if (!user) return;
    setLoadingProfiles(true);
    try {
      const swipesSnap = await getDocs(
        query(collection(db, 'swipes'), where('swiperId', '==', user.uid))
      );
      const swipedIds = new Set(swipesSnap.docs.map((d) => d.data().swipedId));
      swipedIds.add(user.uid);

      const profilesSnap = await getDocs(
        query(
          collection(db, 'users'),
          where('profileCompleted', '==', true),
          where('isActive', '==', true)
        )
      );

      const allProfiles = profilesSnap.docs
        .map((d) => d.data() as UserProfile)
        .filter((p) => !swipedIds.has(p.uid))
        .sort(() => Math.random() - 0.5);

      setProfiles(allProfiles);
      setCurrentIndex(0);

      // Fetch NIM insights for first 3 profiles
      if (profile && allProfiles.length > 0) {
        allProfiles.slice(0, 3).forEach(async (p) => {
          try {
            const res = await fetch('/api/nim', {
              method: 'POST',
              headers: { 'Content-Type': 'application/json' },
              body: JSON.stringify({
                action: 'compatibility',
                payload: { myProfile: profile, theirProfile: p },
              }),
            });
            if (res.ok) {
              const { insight } = await res.json();
              setNimInsights((prev) => ({ ...prev, [p.uid]: insight }));
            }
          } catch { /* NIM unavailable - graceful degradation */ }
        });
      }
    } catch (err) {
      console.error('Error fetching profiles:', err);
    } finally {
      setLoadingProfiles(false);
    }
  }, [user, profile]);

  useEffect(() => {
    if (user && profile) fetchProfiles();
  }, [user, profile, fetchProfiles]);

  const showToast = (msg: string) => {
    setToast(msg);
    if (toastTimer.current) clearTimeout(toastTimer.current);
    toastTimer.current = setTimeout(() => setToast(null), 2200);
  };

  const handleSwipe = async (direction: 'left' | 'right') => {
    if (!user || !profile || currentIndex >= profiles.length) return;
    const swipedProfile = profiles[currentIndex];

    try {
      await addDoc(collection(db, 'swipes'), {
        swiperId: user.uid,
        swipedId: swipedProfile.uid,
        direction,
        timestamp: new Date().toISOString(),
      });

      if (direction === 'right') {
        const reverseSnap = await getDocs(
          query(
            collection(db, 'swipes'),
            where('swiperId', '==', swipedProfile.uid),
            where('swipedId', '==', user.uid),
            where('direction', '==', 'right')
          )
        );

        if (!reverseSnap.empty) {
          const chatId = [user.uid, swipedProfile.uid].sort().join('_');
          await setDoc(doc(db, 'chats', chatId), {
            id: chatId, type: 'individual',
            participants: [user.uid, swipedProfile.uid],
            participantNames: {
              [user.uid]: profile.codeName,
              [swipedProfile.uid]: swipedProfile.codeName,
            },
            lastMessage: `${profile.codeName} and ${swipedProfile.codeName} matched!`,
            lastMessageAt: new Date().toISOString(),
            createdAt: new Date().toISOString(),
          });

          await addDoc(collection(db, 'matches'), {
            user1: user.uid, user2: swipedProfile.uid,
            user1CodeName: profile.codeName, user2CodeName: swipedProfile.codeName,
            chatId, createdAt: new Date().toISOString(),
          });

          await Promise.all([
            updateDoc(doc(db, 'users', user.uid), { collaborationCount: increment(1) }),
            updateDoc(doc(db, 'users', swipedProfile.uid), { collaborationCount: increment(1) }),
            addDoc(collection(db, 'messages'), {
              chatId, senderId: 'system', senderCodeName: 'System',
              text: `${profile.codeName} and ${swipedProfile.codeName} matched! Start collaborating.`,
              timestamp: new Date().toISOString(), type: 'system',
            }),
          ]);

          setShowMatch(swipedProfile);
        }
      }
    } catch (err) {
      console.error('Error recording swipe:', err);
    }

    setTimeout(() => setCurrentIndex((prev) => prev + 1), 300);
  };

  if (loading || !profile) {
    return <div className="loading-page"><div className="spinner" /></div>;
  }

  const currentProfile = profiles[currentIndex];

  return (
    <div className="app-shell">
      <header className="c-header">
        <span className="c-logo">Campus<span>Link</span></span>
        <span className="swipe-count">{Math.max(0, profiles.length - currentIndex)} left</span>
      </header>

      <div className="swipe-wrap">
        <div className="swipe-top">
          <div className="swipe-title">Discover</div>
        </div>

        <div className="card-stack">
          {loadingProfiles ? (
            <div className="empty-swipe"><div className="spinner" /></div>
          ) : currentIndex >= profiles.length ? (
            <div className="empty-swipe">
              <div className="big-icon">🌙</div>
              <p>You&apos;ve seen everyone<br />for now. Check back later.</p>
              <button className="interested-btn" style={{ marginTop: 12 }} onClick={fetchProfiles}>
                Refresh
              </button>
            </div>
          ) : (
            <>
              {currentIndex + 2 < profiles.length && (
                <SwipeCard
                  key={profiles[currentIndex + 2]?.uid}
                  profile={profiles[currentIndex + 2]}
                  onSwipe={() => { }}
                  isTop={false}
                  stackIndex={2}
                />
              )}
              {currentIndex + 1 < profiles.length && (
                <SwipeCard
                  key={profiles[currentIndex + 1]?.uid}
                  profile={profiles[currentIndex + 1]}
                  onSwipe={() => { }}
                  isTop={false}
                  stackIndex={1}
                />
              )}
              <SwipeCard
                ref={topCardRef}
                key={currentProfile.uid}
                profile={currentProfile}
                onSwipe={handleSwipe}
                isTop={true}
                stackIndex={0}
                nimInsight={nimInsights[currentProfile.uid]}
              />
            </>
          )}
        </div>

        {!loadingProfiles && currentIndex < profiles.length && (
          <div className="swipe-actions">
            <button className="action-btn reject" onClick={() => topCardRef.current?.triggerSwipe('left')}>✗</button>
            <button className="action-btn skip" onClick={() => topCardRef.current?.triggerSwipe('left')}>↩</button>
            <button className="action-btn accept" onClick={() => topCardRef.current?.triggerSwipe('right')}>✓</button>
          </div>
        )}
      </div>

      {showMatch && (
        <div className="match-popup">
          <div className="match-label">It&apos;s a Match!</div>
          <div className="match-sub">You and {showMatch.codeName} can now collaborate</div>
          <div className="match-avatars">
            <div className="match-av">
              {profile.codeName.split(/\s+/).map((w) => w[0]).join('').slice(0, 2).toUpperCase()}
            </div>
            <div className="match-x">×</div>
            <div className="match-av">
              {showMatch.codeName.split(/\s+/).map((w) => w[0]).join('').slice(0, 2).toUpperCase()}
            </div>
          </div>
          <button className="match-btn" onClick={() => { setShowMatch(null); router.push('/chat'); }}>
            Open Chat
          </button>
          <button className="match-skip" onClick={() => setShowMatch(null)}>Maybe later</button>
        </div>
      )}

      {toast && <div className="toast">{toast}</div>}
      <BottomNav />
    </div>
  );
}
