'use client';

import { useState, useRef, useCallback, useEffect, forwardRef, useImperativeHandle } from 'react';
import { UserProfile } from '@/lib/types';

interface SwipeCardProps {
  profile: UserProfile;
  onSwipe: (direction: 'left' | 'right') => void;
  isTop: boolean;
  stackIndex: number;
  nimInsight?: string;
}

export interface SwipeCardHandle {
  triggerSwipe: (dir: 'left' | 'right') => void;
}

const SwipeCard = forwardRef<SwipeCardHandle, SwipeCardProps>(
  ({ profile, onSwipe, isTop, stackIndex, nimInsight }, ref) => {
    const cardRef = useRef<HTMLDivElement>(null);
    const isDragging = useRef(false);
    const startX = useRef(0);
    const startY = useRef(0);
    const currentDx = useRef(0);
    const [decisionOpacity, setDecisionOpacity] = useState({ left: 0, right: 0 });

    const getInitials = (name: string) =>
      name.split(/\s+/).map((w) => w[0]?.toUpperCase() ?? '').join('').slice(0, 2);

    // Expose triggerSwipe so parent buttons can animate the card off screen
    useImperativeHandle(ref, () => ({
      triggerSwipe(dir: 'left' | 'right') {
        if (!cardRef.current || !isTop) return;
        const tx = dir === 'right' ? 130 : -130;
        const rot = dir === 'right' ? 20 : -20;
        cardRef.current.style.transition = 'transform 0.4s cubic-bezier(0.4,0,0.2,1)';
        cardRef.current.style.transform = `translateX(${tx}%) rotate(${rot}deg)`;
        setTimeout(() => onSwipe(dir), 350);
      },
    }));

    const applyDrag = useCallback(
      (dx: number, dy: number) => {
        currentDx.current = dx;
        const rot = dx * 0.07;
        if (cardRef.current) {
          cardRef.current.style.transform = `translateX(${dx}px) translateY(${dy * 0.3}px) rotate(${rot}deg)`;
        }
        const threshold = 60;
        if (dx > threshold) {
          setDecisionOpacity({ left: 0, right: Math.min((dx - threshold) / 60, 1) });
        } else if (dx < -threshold) {
          setDecisionOpacity({ left: Math.min((-dx - threshold) / 60, 1), right: 0 });
        } else {
          setDecisionOpacity({ left: 0, right: 0 });
        }
      },
      []
    );

    const finishDrag = useCallback(() => {
      if (!isDragging.current) return;
      isDragging.current = false;
      if (cardRef.current) {
        cardRef.current.style.transition = 'transform 0.4s cubic-bezier(0.4,0,0.2,1)';
      }
      const dx = currentDx.current;
      if (dx > 80) {
        if (cardRef.current) cardRef.current.style.transform = 'translateX(130%) rotate(20deg)';
        setTimeout(() => onSwipe('right'), 350);
      } else if (dx < -80) {
        if (cardRef.current) cardRef.current.style.transform = 'translateX(-130%) rotate(-20deg)';
        setTimeout(() => onSwipe('left'), 350);
      } else {
        if (cardRef.current) cardRef.current.style.transform = '';
        setDecisionOpacity({ left: 0, right: 0 });
      }
      currentDx.current = 0;
    }, [onSwipe]);

    // Global mouse/touch listeners so fast moves don't lose drag
    useEffect(() => {
      if (!isTop) return;

      const onMouseMove = (e: MouseEvent) => {
        if (!isDragging.current) return;
        applyDrag(e.clientX - startX.current, e.clientY - startY.current);
      };
      const onMouseUp = () => finishDrag();
      const onTouchMove = (e: TouchEvent) => {
        if (!isDragging.current) return;
        applyDrag(
          e.touches[0].clientX - startX.current,
          e.touches[0].clientY - startY.current
        );
      };
      const onTouchEnd = () => finishDrag();

      window.addEventListener('mousemove', onMouseMove);
      window.addEventListener('mouseup', onMouseUp);
      window.addEventListener('touchmove', onTouchMove, { passive: true });
      window.addEventListener('touchend', onTouchEnd);

      return () => {
        window.removeEventListener('mousemove', onMouseMove);
        window.removeEventListener('mouseup', onMouseUp);
        window.removeEventListener('touchmove', onTouchMove);
        window.removeEventListener('touchend', onTouchEnd);
      };
    }, [isTop, applyDrag, finishDrag]);

    const onPointerDown = (e: React.MouseEvent | React.TouchEvent) => {
      if (!isTop) return;
      isDragging.current = true;
      currentDx.current = 0;
      const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
      const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
      startX.current = clientX;
      startY.current = clientY;
      if (cardRef.current) cardRef.current.style.transition = 'none';
    };

    const scale = isTop ? 1 : 1 - stackIndex * 0.04;
    const translateY = isTop ? 0 : stackIndex * 10;
    const zIndex = 10 - stackIndex;

    return (
      <div
        ref={cardRef}
        className="swipe-card"
        style={{
          zIndex,
          transform: isTop ? '' : `scale(${scale}) translateY(${translateY}px)`,
          opacity: stackIndex > 2 ? 0 : 1,
          pointerEvents: isTop ? 'auto' : 'none',
          userSelect: 'none',
        }}
        onMouseDown={onPointerDown}
        onTouchStart={onPointerDown}
      >
        {/* Decision labels */}
        <div className="swipe-decision-left" style={{ opacity: decisionOpacity.left }}>✗ PASS</div>
        <div className="swipe-decision-right" style={{ opacity: decisionOpacity.right }}>✓ CONNECT</div>

        {/* Card header */}
        <div className="card-bg">
          <div className="avatar-circle">{getInitials(profile.codeName)}</div>
          <div className="codename-tag">{profile.codeName}</div>
          <div className="score-tag">⬡ {profile.score}</div>
        </div>

        {/* Card body */}
        <div className="card-body">
          <div className="card-college">
            {profile.college} · {profile.isStudent ? 'Student' : 'Professional'}
          </div>
          <div className="card-about">&ldquo;{profile.aboutMe}&rdquo;</div>

          <div className="score-row">
            <div className="score-item">
              <span className="score-num">{profile.cgpa}</span>
              <span className="score-lbl">CGPA</span>
            </div>
            <div className="score-item">
              <span className="score-num">{profile.hackathons.length}</span>
              <span className="score-lbl">Hackathons</span>
            </div>
            <div className="score-item">
              <span className="score-num">{profile.papers}</span>
              <span className="score-lbl">Papers</span>
            </div>
            <div className="score-item">
              <span className="score-num">{profile.collaborationCount}</span>
              <span className="score-lbl">Collabs</span>
            </div>
          </div>

          <div className="skills-section">
            <div className="skills-label">Tech Skills</div>
            <div className="skills-row">
              {profile.techSkills.slice(0, 5).map((s) => (
                <span key={s} className="skill-chip">{s}</span>
              ))}
            </div>
          </div>

          <div className="skills-section">
            <div className="skills-label">Non-Tech</div>
            <div className="skills-row">
              {profile.nonTechSkills.slice(0, 3).map((s) => (
                <span key={s} className="skill-chip non-tech">{s}</span>
              ))}
            </div>
          </div>

          {nimInsight && (
            <div className="nim-insight">
              <span><span className="nim-badge">✦ AI Insight</span></span>
              {nimInsight}
            </div>
          )}
        </div>
      </div>
    );
  }
);

SwipeCard.displayName = 'SwipeCard';
export default SwipeCard;
